const KD = {
  _key: "kd_store",
  // load() {
  //   try {
  //     const s = localStorage.getItem(this._key);
  //     return s ? JSON.parse(s) : JSON.parse(JSON.stringify(KD_DEFAULT));
  //   } catch (e) {
  //     return JSON.parse(JSON.stringify(KD_DEFAULT));
  //   }
  // },
  load() {
    try {
      const saved = localStorage.getItem(this._key);
      if (!saved) return JSON.parse(JSON.stringify(KD_DEFAULT));
      const stored = JSON.parse(saved);

      // products.js আপডেট হলে localStorage ও আপডেট হবে
      // KD_DEFAULT এর version দিয়ে তুলনা করা হচ্ছে
      if (!stored._version || stored._version !== KD_DEFAULT._version) {
        // নতুন version পেলে default দিয়ে merge করো
        const merged = JSON.parse(JSON.stringify(KD_DEFAULT));
        merged._version = KD_DEFAULT._version;
        this.save(merged);
        return merged;
      }
      return stored;
    } catch (e) {
      return JSON.parse(JSON.stringify(KD_DEFAULT));
    }
  },
  save(d) {
    try {
      localStorage.setItem(this._key, JSON.stringify(d));
    } catch (e) {}
  },
  get() {
    return this.load();
  },
  getProducts() {
    return this.load().products || [];
  },
  getCategories() {
    return this.load().categories || [];
  },
  getHeroSlides() {
    return this.load().heroSlides || [];
  },
  getOfferBanners() {
    return this.load().offerBanners || [];
  },
  getConfig() {
    return this.load().config || KD_DEFAULT.config;
  },
  setProducts(a) {
    const d = this.load();
    d.products = a;
    this.save(d);
  },
  setCategories(a) {
    const d = this.load();
    d.categories = a;
    this.save(d);
  },
  setHeroSlides(a) {
    const d = this.load();
    d.heroSlides = a;
    this.save(d);
  },
  setOfferBanners(a) {
    const d = this.load();
    d.offerBanners = a;
    this.save(d);
  },
  setConfig(c) {
    const d = this.load();
    d.config = c;
    this.save(d);
  },
  getOrders() {
    try {
      return JSON.parse(localStorage.getItem("kd_orders") || "[]");
    } catch (e) {
      return [];
    }
  },
  addOrder(o) {
    const orders = this.getOrders();
    o.id = "ORD-" + Date.now();
    o.time = new Date().toLocaleString("bn-BD");
    o.status = "pending";
    orders.unshift(o);
    localStorage.setItem("kd_orders", JSON.stringify(orders));
    return o;
  },
  updateOrderStatus(id, s) {
    const orders = this.getOrders();
    const o = orders.find((x) => x.id === id);
    if (o) o.status = s;
    localStorage.setItem("kd_orders", JSON.stringify(orders));
  },
  track(e, d = {}) {
    try {
      const a = JSON.parse(localStorage.getItem("kd_analytics") || "{}");
      const t = new Date().toISOString().split("T")[0];
      if (!a[t])
        a[t] = {
          visits: 0,
          orders: 0,
          cartAdds: 0,
          wishlistAdds: 0,
          productViews: {},
        };
      const day = a[t];
      if (e === "visit") day.visits++;
      if (e === "order") day.orders++;
      if (e === "cartAdd") day.cartAdds++;
      if (e === "wishlistAdd") day.wishlistAdds++;
      if (e === "productView") {
        day.productViews[d.id] = (day.productViews[d.id] || 0) + 1;
      }
      localStorage.setItem("kd_analytics", JSON.stringify(a));
    } catch (e) {}
  },
  getAnalytics() {
    try {
      return JSON.parse(localStorage.getItem("kd_analytics") || "{}");
    } catch (e) {
      return {};
    }
  },
  reset() {
    localStorage.removeItem(this._key);
  },
};
